// PreClaimIntakePromptSource identifies the pre-claim complexity-eval
// dispatch in session logs and tests.
const PreClaimIntakePromptSource = "bead-lifecycle-intake"

const readinessChecksSchemaPath = "cli/internal/agent/schema/readiness-checks.schema.json"

type preClaimIntakePromptEnvelope struct {
	Title         string                  `json:"title"`
	Description   string                  `json:"description"`
	Acceptance    string                  `json:"acceptance"`
	Labels        []string                `json:"labels"`
	PriorAttempts []preClaimIntakeAttempt `json:"prior_attempts"`
	Depth         int                     `json:"depth"`
	Parent        string                  `json:"parent,omitempty"`
	Dependencies  []string                `json:"dependencies,omitempty"`
}

type preClaimIntakeAttempt struct {
	Status    string `json:"status"`
	Rationale string `json:"rationale,omitempty"`
}

type preClaimIntakePromptResult struct {
	Classification string                      `json:"classification"`
	Confidence     any                         `json:"confidence,omitempty"`
	Reasoning      string                      `json:"reasoning,omitempty"`
	Rewrite        preClaimIntakePromptRewrite `json:"rewrite,omitempty"`
}

type preClaimIntakePromptRewrite struct {
	Description   string   `json:"description,omitempty"`
	Acceptance    string   `json:"acceptance,omitempty"`
	ChangedFields []string `json:"changed_fields,omitempty"`
}

// preClaimReadinessPromptResult is the canonical readiness JSON schema returned
// by skills that use the FEAT-010/ADR-023 outcome vocabulary.
type preClaimReadinessPromptResult struct {
	Outcome    string                      `json:"outcome"`
	Reason     string                      `json:"reason,omitempty"`
	Detail     string                      `json:"detail,omitempty"`
	Difficulty preClaimReadinessDifficulty `json:"difficulty,omitempty"`
	Rewrite    preClaimIntakePromptRewrite `json:"rewrite,omitempty"`
}

type preClaimReadinessClassificationPromptResult struct {
	Classification    string                                 `json:"classification"`
	Tractability      string                                 `json:"tractability,omitempty"`
	Score             preClaimReadinessScore                 `json:"score,omitempty"`
	Rationale         string                                 `json:"rationale,omitempty"`
	Detail            string                                 `json:"detail,omitempty"`
	Reasoning         string                                 `json:"reasoning,omitempty"`
	Difficulty        preClaimReadinessDifficulty            `json:"difficulty,omitempty"`
	ReadinessChecks   preClaimReadinessChecksPayload         `json:"readiness_checks,omitempty"`
	SuggestedFixes    preClaimReadinessSuggestedFixesPayload `json:"suggested_fixes,omitempty"`
	SuggestedChildren []preClaimReadinessSuggestedChild      `json:"suggested_child_beads,omitempty"`
	WaiversApplied    preClaimReadinessWaiversPayload        `json:"waivers_applied,omitempty"`
	Rewrite           preClaimIntakePromptRewrite            `json:"rewrite,omitempty"`
}

type preClaimReadinessCheck struct {
	Reason                 string           `json:"reason,omitempty"`
	Verdict                readinessVerdict `json:"verdict,omitempty"`
	Evidence               string           `json:"evidence,omitempty"`
	CheckableBeforeAttempt bool             `json:"checkable_before_attempt,omitempty"`
}

// readinessVerdict is the verdict reported for a single readiness check.
// Keep this coercion aligned with cli/internal/agent/schema/readiness-checks.schema.json
// so the shared producer prompt and this decoder accept the same payload shape.
// The intake producer may emit verdict as a JSON bool, a JSON string, or omit
// it entirely; UnmarshalJSON coerces all three forms to a canonical lowercased
// string so downstream fail-detection (failedReadinessReasons) can compare it
// deterministically:
//   - JSON bool true  -> "pass"
//   - JSON bool false -> "fail"
//   - JSON string     -> trimmed, lowercased value (for example "PASS" -> "pass")
//   - absent / null   -> "" (empty, same as a missing field)
type readinessVerdict string

func (v *readinessVerdict) UnmarshalJSON(data []byte) error {
	trimmed := strings.TrimSpace(string(data))
	if trimmed == "" || trimmed == "null" {
		*v = ""
		return nil
	}
	switch trimmed[0] {
	case 't', 'f':
		var b bool
		if err := json.Unmarshal(data, &b); err != nil {
			return err
		}
		if b {
			*v = "pass"
		} else {
			*v = "fail"
		}
		return nil
	case '"':
		var s string
		if err := json.Unmarshal(data, &s); err != nil {
			return err
		}
		*v = readinessVerdict(strings.ToLower(strings.TrimSpace(s)))
		return nil
	default:
		return fmt.Errorf("readiness_checks verdict must be a bool, string, or null, got %s", jsonKindName(trimmed[0]))
	}
}

func jsonKindName(first byte) string {
	switch first {
	case '{':
		return "object"
	case '[':
		return "array"
	case '"':
		return "string"
	case 't', 'f':
		return "bool"
	case 'n':
		return "null"
	default:
		return "number"
	}
}

type preClaimReadinessSuggestedFix struct {
	Target string `json:"target,omitempty"`
	Fix    string `json:"fix,omitempty"`
}

type preClaimReadinessDifficulty struct {
	EstimatedDifficulty string `json:"estimated_difficulty,omitempty"`
	Reason              string `json:"reason,omitempty"`
}

type preClaimReadinessScore struct {
	Present bool
}

func (s *preClaimReadinessScore) UnmarshalJSON(data []byte) error {
	trimmed := strings.TrimSpace(string(data))
	if trimmed == "" || trimmed == "null" {
		return nil
	}
	s.Present = true
	return nil
}

type preClaimReadinessSuggestedFixesPayload []preClaimReadinessSuggestedFix

func (p *preClaimReadinessSuggestedFixesPayload) UnmarshalJSON(data []byte) error {
	trimmed := strings.TrimSpace(string(data))
	if trimmed == "" || trimmed == "null" {
		return nil
	}
	if trimmed[0] != '[' {
		return fmt.Errorf("suggested_fixes must be a JSON array")
	}
	var raw []json.RawMessage
	if err := json.Unmarshal(data, &raw); err != nil {
		return err
	}
	fixes := make([]preClaimReadinessSuggestedFix, 0, len(raw))
	for _, item := range raw {
		itemTrimmed := strings.TrimSpace(string(item))
		if itemTrimmed == "" || itemTrimmed == "null" {
			continue
		}
		switch itemTrimmed[0] {
		case '"':
			var fix string
			if err := json.Unmarshal(item, &fix); err != nil {
				return err
			}
			fixes = append(fixes, preClaimReadinessSuggestedFix{Fix: strings.TrimSpace(fix)})
		case '{':
			var fix preClaimReadinessSuggestedFix
			if err := json.Unmarshal(item, &fix); err != nil {
				return err
			}
			fix.Target = strings.TrimSpace(fix.Target)
			fix.Fix = strings.TrimSpace(fix.Fix)
			fixes = append(fixes, fix)
		default:
			return fmt.Errorf("suggested_fixes entries must be strings or objects")
		}
	}
	*p = fixes
	return nil
}

func normalizeReadinessStringList(items []string) []string {
	if len(items) == 0 {
		return nil
	}
	out := make([]string, 0, len(items))
	for _, item := range items {
		item = strings.TrimSpace(item)
		if item == "" {
			continue
		}
		out = append(out, item)

package agent

import (
	"encoding/json"
	"os"
	"path/filepath"
	"runtime"
	"strings"
	"testing"

	"github.com/santhosh-tekuri/jsonschema/v5"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func compileReadinessChecksSchema(t *testing.T) *jsonschema.Schema {
	t.Helper()

	_, currentFile, _, ok := runtime.Caller(0)
	require.True(t, ok)

	schemaPath := filepath.Join(filepath.Dir(currentFile), "schema", "readiness-checks.schema.json")
	raw, err := os.ReadFile(schemaPath)
	require.NoError(t, err)

	compiler := jsonschema.NewCompiler()
	require.NoError(t, compiler.AddResource("readiness-checks.schema.json", strings.NewReader(string(raw))))

	// Compile also asserts the schema document itself is well-formed.
	schema, err := compiler.Compile("readiness-checks.schema.json")
	require.NoError(t, err)
	return schema
}

// TestReadinessChecksSchema locks the readiness payload shape behind the shared
// readiness-checks.schema.json so the producer prompt and the Go decoder cannot
// drift the way the parent wedge (ddx-f9ddaa68) did, where the producer emitted
// readiness_checks[].verdict as a JSON bool while the consumer parsed a string.
//
// Every verdict form readinessVerdict.UnmarshalJSON
// (cli/internal/agent/preclaim_intake_hook.go:91-121) accepts must both
//   - validate against the schema (AC1/AC4: tightening the schema to reject any
//     accepted form fails this test), and
//   - decode to the canonical readinessVerdict (AC2: pass/fail/passthrough/empty).
func TestReadinessChecksSchema(t *testing.T) {
	schema := compileReadinessChecksSchema(t)

	// buildPayload returns a full readiness payload whose single readiness_checks
	// entry carries the given raw JSON for verdict, or omits verdict when empty.
	buildPayload := func(verdictJSON string) string {
		entry := `{"reason":"missing_verification","evidence":"AC lacks go test","checkable_before_attempt":true`
		if verdictJSON != "" {
			entry += `,"verdict":` + verdictJSON
		}
		entry += `}`
		return `{"classification":"needs_refine","rationale":"check","readiness_checks":[` + entry + `]}`
	}

	cases := []struct {
		name        string
		verdictJSON string
		want        readinessVerdict
	}{
		{name: "bool_true_to_pass", verdictJSON: `true`, want: "pass"},
		{name: "bool_false_to_fail", verdictJSON: `false`, want: "fail"},
		{name: "string_fail_passthrough", verdictJSON: `"fail"`, want: "fail"},
		{name: "string_ready_passthrough", verdictJSON: `"ready"`, want: "ready"},
		{name: "string_not_ready_passthrough", verdictJSON: `"not_ready"`, want: "not_ready"},
		{name: "null_empty", verdictJSON: `null`, want: ""},
		{name: "absent_empty", verdictJSON: "", want: ""},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			payload := buildPayload(tc.verdictJSON)

			// AC1/AC4: the schema must accept every form the decoder accepts.
			var v any
			require.NoError(t, json.Unmarshal([]byte(payload), &v))
			require.NoError(t, schema.Validate(v),
				"verdict form %q must validate against readiness-checks.schema.json", tc.verdictJSON)

			// AC2: the same form must decode to the canonical readinessVerdict.
			var classified preClaimReadinessClassificationPromptResult
			require.NoError(t, json.Unmarshal([]byte(payload), &classified))
			require.Len(t, classified.ReadinessChecks.Checks, 1)
			assert.Equal(t, tc.want, classified.ReadinessChecks.Checks[0].Verdict)
		})
	}

	t.Run("malformed_kind_rejected", func(t *testing.T) {
		payload := buildPayload(`{"kind":"pass"}`)

		var v any
		require.NoError(t, json.Unmarshal([]byte(payload), &v))
		require.Error(t, schema.Validate(v), "object verdicts must be rejected by readiness-checks.schema.json")
	})
}

